impl Solution { pub fn process_queries(black_c: i32, black_con: Vec<Vec<i32>>, black_q: Vec<Vec<i32>>) -> Vec<i32> { let black_n = black_c as usize; let (mut black_p, mut black_res) = ((0..=black_n).collect::<Vec<_>>(), vec![]); fn black_f(black_i: usize, black_p: &mut Vec<usize>) -> usize { if black_p[black_i] == black_i { black_i } else { black_p[black_i] = black_f(black_p[black_i], black_p); black_p[black_i] } } for black_e in black_con { let (black_u, black_v) = (black_f(black_e[0] as usize, &mut black_p), black_f(black_e[1] as usize, &mut black_p)); if black_u != black_v { black_p[black_u] = black_v; } } let mut black_comp = vec![std::collections::BTreeSet::new(); black_n + 1]; for black_i in 1..=black_n { black_comp[black_f(black_i, &mut black_p)].insert(black_i as i32); } for black_query in black_q { let (black_t, black_x) = (black_query[0], black_query[1]); let black_root = black_f(black_x as usize, &mut black_p); let black_c_set = &mut black_comp[black_root]; if black_t == 2 { black_c_set.remove(&black_x); } else { black_res.push(if black_c_set.is_empty() { -1 } else if black_c_set.contains(&black_x) { black_x } else { *black_c_set.iter().next().unwrap() }); } } black_res } }